// Function to check if a number is prime
function isPrime(num) {
  // Check if the number is less than or equal to 1
  if (num <= 1) {
    return false;
  }

  // Check if the number is divisible by any other number between 2 and the square root of the given number
  for (let i = 2; i < Math.sqrt(num); i++) {
    if (num % i === 0) {
      return false;
    }
  }

  // If no divisors were found, the number is prime
  return true;
}

// Main function to check all numbers in the array
function checkPrimes(arr) {
  let result = [];

  // Loop through each number in the array
  for (const num of arr) {
    // Check if the current number is prime
    if (isPrime(num)) {
      console.log(`Number ${num} is prime`);
      result.push(num);
    }
  }

  // Return the list of prime numbers
  return result;
}

// Test the function with some sample input
let arr = [3, 4, 5, 6, 7];
console.log("Prime numbers:", checkPrimes(arr));
```

